import React from 'react';

const About: React.FC = () => {
  return (
    <section className="about">
      <h1>About EV Smart Maintenance System</h1>
      <p>The Smart Maintenance System is designed to help users manage and maintain their electric vehicles effectively. With advanced diagnostic tools and user-friendly interfaces, it ensures the longevity and performance of your EV. Our system provides real-time analysis, maintenance reminders, and support resources.</p>
      <h2>Features</h2>
      <ul>
        <li>Real-time diagnostics</li>
        <li>Maintenance scheduling</li>
        <li>Support documentation</li>
        <li>User-friendly interface</li>
      </ul>
    </section>
  );
};

export default About;
